    ORA #$40
    BNE L94C0

; ============================================================
; MODEM_REG_WRITE_WAIT
; ============================================================
L94B2:
    CMP #$40                            ; workspace
    BCC L94C0
    CMP #$60
    BCS L94BE
    ORA #$80
    BNE L94C0
L94BE:
    EOR #$C0
L94C0:
    RTS

; --- MODEM_REG_WRITE_WAIT ---
; Send bytes from $C100 buffer via protocol engine
MODEM_REG_WRITE_WAIT:
    STY $C14D
    LDY #$00

; ============================================================
; MODEM_REG_READ_STATUS
; ============================================================
L94C6:
    LDA $C100,Y
    INY
    CPY $C14D
    PHP
    JSR L96C9
    PLP
    BCC L94C6
    RTS

; ============================================================
; MODEM_WAIT_READY
; ============================================================

; --- MODEM_REG_READ_STATUS ---
; Read modem status into $C100 buffer
MODEM_REG_READ_STATUS:
    LDY #$00
L94D7:
    JSR L96CC
    STA $C100,Y
    INY
    BCC L94D7
    LDA $8034
    RTS                                 ; MODEM_REG_SELECT

; --- MODEM_WAIT_READY ---
; Wait for modem TX ready, then send byte
MODEM_WAIT_READY:
    PHA
    LDX #$00
L94E7:
    JSR MODEM_REG_READ
    TAX

; ============================================================
; MODEM_REG_READ
; ============================================================
    BPL L94E7
    PLA                                 ; MODEM_REG_SELECT
    LDX #$04

; --- MODEM_REG_WRITE ---
; Write value to modem register (X=reg, A=value)
MODEM_REG_WRITE:
    PHP                                 ; MODEM_DATA
    SEI
    STX ACIA_DATA
    STA ACIA_STATUS
    PLP
    RTS

; --- MODEM_REG_READ ---
; Read modem register (X=reg, returns A=value)
MODEM_REG_READ:
    PHP
    SEI
    STX ACIA_DATA
    LDA ACIA_STATUS
    LDA ACIA_STATUS
    PLP
    RTS
