; --- PROTO_INIT_REGS ---
; Initialize modem registers for protocol mode
PROTO_INIT_REGS:
    LDX #$02
    LDA #$40
    JSR MODEM_REG_WRITE
    LDX #$06
    LDA #$05                            ; workspace
    JMP MODEM_REG_WRITE

; --- PROTO_START_SESSION ---
; Start protocol session (set connected state)
PROTO_START_SESSION:
    BIT $8038
    BVC L96F3
    LDX #$04
    JMP MODEM_SEND_CMD
L96F3:
    LDA $C20E
